/**
 * REVENANT V31-F2 — "Block 9.5: Registry Lookup & Payload Builder" (TIER 2)
 * Upgraded to include Tax/Mobile providers and Vault-sourced secrets.
 */

const items = $input.all();
const returnData = [];

// ---------------------------------------------------------------------------
// MOCK PROVIDER REGISTRY (Vault-Sourced)
// ---------------------------------------------------------------------------
const REGISTRY = {
  UZBEKENERGO: {
    endpoint: 'https://api.uzbekenergo.uz/v2/payments/accept',
    method: 'POST',
    auth_header_name: 'X-UZBEKENERGO-API-KEY',
    auth_secret: $vars.VAULT_UZBEKENERGO_SECRET || 'fallback_uze_sk', // 🔒 Sourced from Vault
    payload_map: [
      { source_field: 'canonical_ticket.payment_request.account_number', target_field: 'pinfl_or_account' },
      { source_field: 'canonical_ticket.payment_request.amount', target_field: 'amount_uzs' },
      { source_field: 'canonical_ticket.trace_id', target_field: 'merchant_trace_id' },
      { source_field: 'canonical_ticket.payment_request.idempotency_key', target_field: 'idempotency_token' },
    ],
  },
  YHXBB_FINES: {
    endpoint: 'https://api.yhxbb.gov.uz/v1/fines/pay',
    method: 'POST',
    auth_header_name: 'Authorization',
    auth_secret: $vars.VAULT_YHXBB_SECRET || 'Bearer fallback_yhxbb_tok', // 🔒 Sourced from Vault
    payload_map: [
      { source_field: 'canonical_ticket.payment_request.protocol_number', target_field: 'resolution_id' },
      { source_field: 'canonical_ticket.payment_request.amount', target_field: 'fine_amount' },
      { source_field: 'canonical_ticket.trace_id', target_field: 'external_ref' },
      { source_field: 'canonical_ticket.payment_request.idempotency_key', target_field: 'dedup_key' },
    ],
  },
  // --- NEW TIER 2 PROVIDER: TAX & INN ---
  TAX_INN: {
    endpoint: 'https://api.soliq.uz/v1/payments/inn',
    method: 'POST',
    auth_header_name: 'X-API-KEY',
    auth_secret: $vars.VAULT_SOLIQ_SECRET || 'fallback_tax_secret', // 🔒 Sourced from Vault
    payload_map: [
      { source_field: 'canonical_ticket.payment_request.inn_number', target_field: 'inn' },
      { source_field: 'canonical_ticket.payment_request.amount', target_field: 'amount' },
      { source_field: 'canonical_ticket.trace_id', target_field: 'trace_id' },
      { source_field: 'canonical_ticket.payment_request.idempotency_key', target_field: 'idempotency_key' },
    ],
  },
  // --- NEW TIER 2 PROVIDER: MOBILE TOP-UP ---
  MOBILE_TOPUP: {
    endpoint: 'https://api.paynet.uz/v3/mobile/charge',
    method: 'POST',
    auth_header_name: 'Authorization',
    auth_secret: $vars.VAULT_PAYNET_SECRET || 'Bearer fallback_paynet_secret', // 🔒 Sourced from Vault
    payload_map: [
      { source_field: 'canonical_ticket.payment_request.phone_number', target_field: 'phone' },
      { source_field: 'canonical_ticket.payment_request.amount', target_field: 'amount' },
      { source_field: 'canonical_ticket.trace_id', target_field: 'transaction_id' },
      { source_field: 'canonical_ticket.payment_request.idempotency_key', target_field: 'idempotency_key' },
    ],
  }
};

function getValueByPath(obj, path) {
  if (!obj || !path) return undefined;
  return path.split('.').reduce((acc, key) => (acc !== undefined && acc !== null ? acc[key] : undefined), obj);
}

function generatePureJSHash(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193);
  }
  return (hash >>> 0).toString(16);
}

for (const item of items) {
  const ticket = item.json.canonical_ticket;

  if (!ticket || !ticket.payment_request) {
    item.json.block95_passed = false;
    item.json.block95_report = 'MISSING_PAYMENT_REQUEST';
    returnData.push(item);
    continue;
  }

  const providerKey = ticket.payment_request.provider_key;
  const providerConfig = REGISTRY[providerKey];

  if (!providerConfig) {
    ticket.ticket_status = 'BLOCKED_UNKNOWN_PROVIDER';
    ticket.block95_passed = false;
    ticket.block95_report = `UNKNOWN_PROVIDER_KEY: ${providerKey || 'undefined'}`;
    item.json.canonical_ticket = ticket;
    returnData.push(item);
    continue;
  }

  const idempotencySeed = [
    providerKey,
    ticket.trace_id,
    ticket.payment_request.account_number || ticket.payment_request.protocol_number || ticket.payment_request.inn_number || ticket.payment_request.phone_number || '',
    ticket.payment_request.amount,
  ].join('|');
  ticket.payment_request.idempotency_key = `bp_${generatePureJSHash(idempotencySeed)}`;

  const body = {};
  for (const fieldMap of providerConfig.payload_map) {
    body[fieldMap.target_field] = getValueByPath(item.json, fieldMap.source_field);
  }

  const dynamicHeaders = [
    { name: providerConfig.auth_header_name, value: providerConfig.auth_secret },
    { name: 'Content-Type', value: 'application/json' }
  ];

  item.json.http_request = {
    endpoint: providerConfig.endpoint,
    method: providerConfig.method,
    body: body,
    headers: dynamicHeaders 
  };

  item.json.__contains_secure_headers = true;
  ticket.block95_passed = true;
  ticket.block95_report = 'REGISTRY_LOOKUP_SUCCESS';
  item.json.canonical_ticket = ticket;

  returnData.push(item);
}

return returnData;

/**
 * REVENANT V31-F2 — "Block 9.7: Universal Response Mapper" (TIER 2)
 * Extended to handle Tax and Mobile Top-Up response schemas.
 */

const items = $input.all();
const returnData = [];

// ---------------------------------------------------------------------------
// MOCK RESPONSE REGISTRY (Extended)
// ---------------------------------------------------------------------------
const RESPONSE_REGISTRY = {
  UZBEKENERGO: {
    response_map: { transaction_id: 'payment_uuid', status: 'state', amount: 'amount_uzs' },
    status_map: { COMPLETED: 'SUCCESS', FAILED: 'FAILED', PENDING: 'PENDING' },
  },
  YHXBB_FINES: {
    response_map: { transaction_id: 'receipt_no', status: 'result', amount: 'fine_amount' },
    status_map: { OK: 'SUCCESS', REJECTED: 'FAILED' },
  },
  TAX_INN: {
    response_map: { transaction_id: 'tax_receipt_id', status: 'payment_status', amount: 'amount_paid' },
    status_map: { PAID: 'SUCCESS', ERROR: 'FAILED', PROCESSING: 'PENDING' },
  },
  MOBILE_TOPUP: {
    response_map: { transaction_id: 'paynet_ref', status: 'status', amount: 'credited_amount' },
    status_map: { SUCCESS: 'SUCCESS', REJECTED: 'FAILED' },
  }
};

const UPSTREAM_TICKET_NODE = 'Block 9.5: Registry Lookup & Payload Builder';

function getValueByPath(obj, path) {
  if (!obj || !path) return undefined;
  return path.split('.').reduce((acc, key) => (acc !== undefined && acc !== null ? acc[key] : undefined), obj);
}

for (const item of items) {
  const rawResponse = (item.json && item.json.body) || item.json || {};

  let ticket = item.json && item.json.canonical_ticket;
  if (!ticket) {
    try {
      ticket = $(UPSTREAM_TICKET_NODE).item.json.canonical_ticket || {};
    } catch (e) {
      ticket = {};
    }
  }

  const providerKey = ticket.payment_request && ticket.payment_request.provider_key;
  const mapConfig = RESPONSE_REGISTRY[providerKey];

  let providerTransactionId = null;
  let mappedStatus = 'UNKNOWN';
  let confirmedAmount = (ticket.payment_request && ticket.payment_request.amount) ?? null;

  if (mapConfig) {
    providerTransactionId = getValueByPath(rawResponse, mapConfig.response_map.transaction_id) ?? null;
    const rawStatus = getValueByPath(rawResponse, mapConfig.response_map.status);
    mappedStatus = mapConfig.status_map[rawStatus] || 'UNKNOWN';

    const responseAmount = getValueByPath(rawResponse, mapConfig.response_map.amount);
    if (responseAmount !== undefined && responseAmount !== null) {
      confirmedAmount = responseAmount;
    }
  }

  const universalReceipt = {
    trace_id: ticket.trace_id || item.json.trace_id || null,
    idempotency_key: (ticket.payment_request && ticket.payment_request.idempotency_key) || null,
    provider_key: providerKey || null,
    provider_transaction_id: providerTransactionId,
    status: mappedStatus,
    amount: confirmedAmount,
    timestamp: new Date().toISOString(),
  };

  ticket.universal_receipt = universalReceipt;
  ticket.block97_passed = mappedStatus === 'SUCCESS';
  ticket.block97_report = mapConfig ? `RESPONSE_MAPPED_${mappedStatus}` : 'UNKNOWN_PROVIDER_AT_RESPONSE_STAGE';

  // CRITICAL SECURITY SCRUB
  delete item.json.__secure_headers;
  delete item.json.__contains_secure_headers;
  delete item.json.provider_request;
  delete item.json.http_request; 

  for (const key of Object.keys(item.json)) {
    if (/secret|api[_-]?key|auth[_-]?token|password|bearer/i.test(key)) {
      delete item.json[key];
    }
  }

  item.json = {
    canonical_ticket: ticket,
    universal_receipt: universalReceipt,
  };

  returnData.push(item);
}

return returnData;
